function nradio_phyname_maxclients(phyname){var ter_max_client=0;if(phyname=="mt7981"||phyname=="mt7993")
ter_max_client+=128;else if(phyname=="mt7628"||phyname=="mt7620"||phyname=="mt7603e"||phyname=="aic8800"||phyname=="swt6652")
ter_max_client+=16;else if(phyname=="mt7612e"||phyname=="mt7663")
ter_max_client+=32;else if(phyname=="mt7915")
ter_max_client+=64;else
ter_max_client+=16;return ter_max_client;}
function nradio_bs_style_fix(){$('th:gt(2)').closest('table').wrap('<div class="table-responsive"/>');}
function nradio_hr_line_style_fix(){$('.dev-line').parent().parent().append('<hr>');}
function nradio_style_onload(){var first=$(document.activeElement);nradio_bs_style_fix();nradio_hr_line_style_fix();$(".main h2").wrapInner("<span></span>");first.focus();}
function nradio_data_format(data,prefix=''){var prefixs=['','K','M','G','T'];if(!data){return new Array(0,prefix);}
var tmp=parseInt(data);var idx=0;$.each(prefixs,function(key,val){if(val!=prefix){++idx;}
else{return false;}});while(tmp>=1024&&idx<prefixs.length)
{tmp=tmp/1024;++idx;}
return new Array(tmp,prefixs[idx]);}
function nradio_rate_format(data,prefix='',unit='bps',fixed=0){var arr=nradio_data_format(data,prefix);return arr[0].toFixed(fixed)+' '+arr[1]+unit;}
function nradio_byte_format(data,prefix='',unit='B',fixed=2){var arr=nradio_data_format(data,prefix);return arr[0].toFixed(fixed)+' '+arr[1]+unit;}
function nradio_checked_set(attr,name='sel_check',value){if(value)
$('input[name="'+name+'"]').each(function(){$(this).prop("checked",true);});else
$('input[name="'+name+'"]:checked').each(function(){$(this).prop("checked",false);});}
function nradio_checked_get(attr,name='sel_check',delim=','){return $('input[name="'+name+'"]:checked').map(function(){return $(this).attr(attr);}).get().join(delim);}
function nradio_array_uniq(arr,delim=","){return Array.from(new Set(arr));}
function nradio_backend_flash(){$.getJSON("/cgi-bin/luci/nradio/status/update");}
function nradio_checker_renew(checker,timeout=100){$.ajax({url:"http://"+checker.url+'?'+(new Date().getTime()),type:'get',timeout:timeout,success:function(data){checker.flag=true;}});}
function nradio_checker_init(url,wait=30,interval=600){return{url:url,flag:false,wait:wait,interval:interval,};}
function nradio_process_show(msg,checker){BootstrapDialog.show({type:BootstrapDialog.TYPE_DEFAULT,title:'',message:msg,closable:false,onshown:function(dialogItself){setInterval(function(){var now=$('.progress-bar').attr('aria-valuenow');++now;if((now>100)||(checker.flag==true)){window.location.href="http://"+checker.url;}
else{if(now>checker.wait){nradio_checker_renew(checker);}
$('.progress-bar').attr('aria-valuenow',now).width(now+'%').html(now+'%');}},checker.interval);}});}
function nradio_checker_proc(url,data,checker,info,hint){var htm='<div class="container">'+'<div class="progress">'+'<div class="progress-bar" role="progressbar" aria-valuenow="0" aria-valuemin="0" aria-valuemax="100" style="width:0%">0%</div>'+'</div><div><p>'+info+'</p>'+'<p class="hint">'+hint+'<p></div>'+'</div>';if(url!=null){(new XHR()).post(url,data,function(){nradio_process_show(htm,checker);});}
else{nradio_process_show(htm,checker);}}
function nradio_network_recheck(getResponse,fcallback){$.ajax({type:"POST",url:"/cgi-bin/luci/admin/system/clock_status",success:function(rv){if(rv&&rv.timestring){if(getResponse){clearInterval(getResponse);getResponse=null;}
if(fcallback){fcallback(rv);return;}}},error:function(xhr,error){console.log('code:',xhr.status);if(xhr.status==403||xhr.status==500){if(getResponse){clearInterval(getResponse);getResponse=null;}
if(fcallback){fcallback();return;}}}});}
function nradio_apply_callback(msgobj,keyobj){var loading=msgobj.loading;var title=msgobj.title;var msg=msgobj.msg;var msg_ok=msgobj.msg_ok;var msg_error=msgobj.msg_error;var id=keyobj.id;var resource=keyobj.resource;var token=keyobj.token;var url=keyobj.url;var url_status=keyobj.url_status;var redirect_buffer=keyobj.redirect_buffer;var htm='<fieldset class="cbi-section" id="cbi-apply-'+id+'">';if(msg_error&&msg_error.length){htm+='<div class="errorbox">'+msg_error+'</div>';}
else{htm+=circling_htm;htm+='<span id="cbi-apply-'+id+'-status">'+msg+'</span>';}
htm+='</fieldset>';var intervalDialog=BootstrapDialog.show({type:BootstrapDialog.TYPE_DEFAULT,title:'',closable:false,cssClass:'nradio_apply_info',message:htm});if(msg_error&&msg_error.length){window.setTimeout(function(){intervalDialog.close();},3000);return;}
var apply_xhr=new XHR();apply_xhr.post(url,{token:token},function(){var checkfinish=function(){apply_xhr.get(url_status,null,function(x){if(x.responseText=='finish')
{var e=document.getElementById('cbi-apply-'+id+'-status');if(e)
{e.innerHTML=msg_ok;window.setTimeout(function(){intervalDialog.close();e.parentNode.style.display='none';if(redirect_buffer){location.href=redirect_buffer;}},1000);}}
else
{var e=document.getElementById('cbi-apply-'+id+'-status');if(e&&x.responseText)e.innerHTML=x.responseText;window.setTimeout(checkfinish,1000);}});}
window.setTimeout(checkfinish,1000);});}
function genarate_loading_box(msgNote,nocircle){var show_htm="";var msgs=msgNote?msgNote:"";if(!nocircle){show_htm+=circling_htm;}
show_htm+='<p class="cbi-value-title width_auto text-center adapt_label_padding">'+msgs+'</p>';return show_htm;}
function create_dial_box(msgNote,nocircle){var htm=genarate_loading_box(msgNote,nocircle);var intervalDialog=BootstrapDialog.show({type:BootstrapDialog.TYPE_DEFAULT,title:'',closable:false,message:htm});return intervalDialog;}
function nradio_network_interval(fcallback,timeInterval,msgNote,dail_box_out){var getResponse=null;var msgs=msgNote?msgNote:"";var dail_box=dail_box_out;if(!dail_box){dail_box=create_dial_box(msgs,1);}
getResponse=setInterval(function(){nradio_network_recheck(getResponse,function(getResponse){dail_box.close();if(fcallback){fcallback();}});},timeInterval);}
function nradio_ajax_submit(name,url=document.URL,msgNote){var url_str=url?url:document.URL;$(name).one("submit",function(e){var onsubmit_orignal=$(name).prop("onsubmit");var onsubmit_orignal_return=false;$(name).prop("onsubmit",function(){onsubmit_orignal_return=onsubmit_orignal.call(this);window.setTimeout(function(){$(name).prop("onsubmit",function(){return onsubmit_orignal});},500);return false;});e.preventDefault();if(!onsubmit_orignal_return){onsubmit_orignal_return=false;return;}
var dail_box=create_dial_box(msgNote);$.ajax({type:"POST",url:$(this).attr('action'),data:$(this).serialize()+'&cbi.apply=1',success:function(data){dail_box.close();location.replace(url_str);},error:function(xhr,error){nradio_network_interval(function(){location.replace(url_str);},2000,msgNote,dail_box);}});});}
